3	import { useEffect, useRef, useState, useCallback, type FormEvent } from 'react';
4	import Link from 'next/link';
5	import s from './page.module.css';
6	import { getSpeechRecognitionConstructor, type SpeechRecognitionInstance } from '@/lib/speechRecognition';
7	import { chatStream, type OmegaRuntimeMetadata } from '@/lib/api';
8	
9	type VoiceState = 'dormant' | 'listening' | 'processing' | 'speaking';
10	
11	type Message = {
12	  role: 'user' | 'omega';
13	  text: string;
14	};
15	
16	/* ────────────────────────────────────────────
17	   Particle field (reduced count for performance)
18	   ──────────────────────────────────────────── */
19	function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
20	  const ctx = canvas.getContext('2d');
21	  if (!ctx) return () => undefined;
22	
23	  const resize = () => {
24	    canvas.width = window.innerWidth;
25	    canvas.height = window.innerHeight;
26	  };
27	  resize();
28	  window.addEventListener('resize', resize);
29	
30	  const particles = Array.from({ length: 200 }, () => {
31	    const angle = Math.random() * Math.PI * 2;
32	    const dist = Math.random() * 40 + 4;
33	    return {
34	      x: Math.cos(angle) * dist,
35	      y: Math.sin(angle) * dist,
36	      z: (Math.random() - 0.5) * 35,
37	      vx: (Math.random() - 0.5) * 0.012,
38	      vy: (Math.random() - 0.5) * 0.012,
39	      vz: (Math.random() - 0.5) * 0.01,
40	      radius: Math.random() * 0.9 + 0.3,
41	      isCyan: Math.random() > 0.5,
42	    };
43	  });
44	
45	  type RGB = [number, number, number];
46	  const magenta: Record<VoiceState, RGB> = { dormant: [140, 0, 200], listening: [200, 0, 130], processing: [90, 0, 230], speaking: [140, 0, 200] };
47	  const cyan: Record<VoiceState, RGB> = { dormant: [0, 150, 185], listening: [0, 185, 215], processing: [0, 210, 240], speaking: [0, 140, 175] };
48	
49	  let rotation = 0;
50	  let raf = 0;
51	
52	  const draw = () => {
53	    const state = getState();
54	    const speed = state === 'processing' ? 1.4 : state === 'speaking' ? 1.0 : state === 'listening' ? 0.9 : 0.5;
55	
56	    ctx.clearRect(0, 0, canvas.width, canvas.height);
57	    rotation += 0.0008 * speed;
58	
59	    const cx = canvas.width / 2;
60	    const cy = canvas.height * 0.32;
61	
62	    for (const p of particles) {
63	      p.x += p.vx * speed;
64	      p.y += p.vy * speed;
65	      p.z += p.vz * speed;
66	      if (Math.abs(p.x) > 45) p.vx *= -1;
67	      if (Math.abs(p.y) > 45) p.vy *= -1;
68	      if (Math.abs(p.z) > 22) p.vz *= -1;
69	    }
70	
71	    const proj = particles.map((p) => {
72	      const rx = p.x * Math.cos(rotation) - p.z * Math.sin(rotation);
73	      const rz = p.x * Math.sin(rotation) + p.z * Math.cos(rotation);
74	      const depth = 180 / (rz + 80);
75	      const [r, g, b] = (p.isCyan ? cyan : magenta)[state];
76	      return { x: cx + rx * depth, y: cy + p.y * depth, alpha: Math.max(0.03, Math.min(0.4, depth * 0.09)), radius: p.radius * depth, r, g, b };
77	    });
78	
79	    for (let i = 0; i < proj.length; i += 1) {
80	      const a = proj[i];
81	      for (let j = i + 1; j < proj.length; j += 4) {
82	        const b = proj[j];
83	        const dx = a.x - b.x;
84	        const dy = a.y - b.y;
85	        const dist = Math.sqrt(dx * dx + dy * dy);
86	        if (dist < 80) {
87	          ctx.beginPath();
88	          ctx.moveTo(a.x, a.y);
89	          ctx.lineTo(b.x, b.y);
90	          ctx.strokeStyle = `rgba(${(a.r + b.r) >> 1},${(a.g + b.g) >> 1},${(a.b + b.b) >> 1},${0.035 * (1 - dist / 80)})`;
91	          ctx.lineWidth = 0.35;
92	          ctx.stroke();
93	        }
94	      }
95	    }
96	
97	    for (const p of proj) {
98	      ctx.beginPath();
99	      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
100	      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha})`;
101	      ctx.fill();
102	    }
103	
104	    raf = requestAnimationFrame(draw);
105	  };
106	
107	  draw();
108	  return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize); };
109	}
110	
111	/* ────────────────────────────────────────────
112	   Audio playback — mp3 or wav
113	   ──────────────────────────────────────────── */
114	function playAudio(base64: string, mimeType: string) {
115	  const binary = atob(base64);
116	  const bytes = new Uint8Array(binary.length);
117	  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
118	  return new Audio(URL.createObjectURL(new Blob([bytes], { type: mimeType || 'audio/mpeg' })));
119	}
120	
121	/* ────────────────────────────────────────────
122	   Tranquility — Neural Presence Shell
123	   ──────────────────────────────────────────── */
124	export default function Tranquility() {
125	  const canvasRef = useRef<HTMLCanvasElement>(null);
126	  const recognitionRef = useRef<SpeechRecognitionInstance | null>(null);
127	  const audioRef = useRef<HTMLAudioElement | null>(null);
128	  const stateRef = useRef<VoiceState>('dormant');
129	  const messagesEndRef = useRef<HTMLDivElement>(null);
130	
131	  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
132	  const [messages, setMessages] = useState<Message[]>([]);
133	  const [streamingText, setStreamingText] = useState('');
134	  const [textInput, setTextInput] = useState('');
135	  const [runtimeMeta, setRuntimeMeta] = useState<OmegaRuntimeMetadata | null>(null);
136	  const [showRuntime, setShowRuntime] = useState(false);
137	  const [operatorMode, setOperatorMode] = useState(false);
138	  const [showLockModal, setShowLockModal] = useState(false);
139	  const [lockToken, setLockToken] = useState('');
140	  const [lockError, setLockError] = useState('');
141	
142	  const setState = useCallback((next: VoiceState) => {
143	    stateRef.current = next;
144	    setVoiceState(next);
145	  }, []);
146	
147	  useEffect(() => {
148	    if (!canvasRef.current) return undefined;
149	    return initParticles(canvasRef.current, () => stateRef.current);
150	  }, []);
151	
152	  useEffect(() => {
153	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
154	  }, [messages, streamingText]);
155	
156	  /* ── TTS (fire-and-forget, non-blocking) ── */
157	  const speakResponse = useCallback(async (text: string) => {
158	    try {
159	      const response = await fetch('/api/tts', {
160	        method: 'POST',
161	        headers: { 'Content-Type': 'application/json' },
162	        body: JSON.stringify({ text: text.slice(0, 2000) }),
163	      });
164	      const data = await response.json();
165	      if (data.audio) {
166	        audioRef.current?.pause();
167	        const audio = playAudio(data.audio, data.mimeType ?? 'audio/mpeg');
168	        audioRef.current = audio;
169	        audio.onended = () => {
170	          if (stateRef.current === 'speaking') setState('dormant');
171	        };
172	        setState('speaking');
173	        await audio.play();
174	      }
175	    } catch {
176	      // Voice is optional — text is always shown.
177	    }
178	  }, [setState]);
179	
180	  /* ── Core chat handler ── */
181	  const sendMessage = useCallback(async (text: string) => {
182	    if (!text.trim()) return;
183	
184	    setMessages((prev) => [...prev, { role: 'user', text }]);
185	    setState('processing');
186	    setStreamingText('');
187	
188	    try {
189	      let reply = '';
190	      const metadata = await chatStream(
191	        { user: text, voiceMode: true },
192	        (chunk) => {
193	          reply += chunk;
194	          setStreamingText(reply);
195	        },
196	      );
197	      setRuntimeMeta(metadata);
198	
199	      const cleanReply = reply.replace(/\[VISUAL_READY\]/g, '').trim() || 'The signal falls quiet.';
200	      setStreamingText('');
201	      setMessages((prev) => [...prev, { role: 'omega', text: cleanReply }]);
202	      setState('dormant');
203	
204	      void speakResponse(cleanReply);
205	    } catch {
206	      const fallback = 'The signal dissolves into the void.';
207	      setStreamingText('');
208	      setMessages((prev) => [...prev, { role: 'omega', text: fallback }]);
209	      setState('dormant');
210	    }
211	  }, [setState, speakResponse]);
212	
213	  /* ── Text submit ── */
214	  const handleSubmit = useCallback((e: FormEvent) => {
215	    e.preventDefault();
216	    const trimmed = textInput.trim();
217	    if (!trimmed || voiceState === 'processing') return;
218	    setTextInput('');
219	    void sendMessage(trimmed);
220	  }, [textInput, voiceState, sendMessage]);
221	
222	  /* ── Voice input ── */
223	  const toggleListening = useCallback(() => {
224	    if (voiceState === 'listening') {
225	      recognitionRef.current?.stop();
226	      setState('dormant');
227	      return;
228	    }
229	
230	    if (voiceState !== 'dormant') return;
231	
232	    const Recognition = getSpeechRecognitionConstructor();
233	    if (!Recognition) return;
234	
235	    const recognition = new Recognition();
236	    recognition.continuous = false;
237	    recognition.interimResults = true;
238	    recognition.lang = 'en-US';
239	    recognitionRef.current = recognition;
240	
241	    recognition.onstart = () => setState('listening');
242	
243	    recognition.onresult = (event) => {
244	      let transcript = '';
245	      for (let i = event.resultIndex; i < event.results.length; i += 1) {
246	        transcript += event.results[i][0].transcript;
247	      }
248	      setTextInput(transcript.trim());
249	      if (event.results[event.results.length - 1]?.isFinal) {
250	        recognition.stop();
251	        const final = transcript.trim();
252	        if (final) {
253	          setTextInput('');
254	          void sendMessage(final);
255	        }
256	      }
257	    };
258	
259	    recognition.onerror = () => setState('dormant');
260	    recognition.onend = () => { if (stateRef.current === 'listening') setState('dormant'); };
261	
262	    recognition.start();
263	  }, [voiceState, setState, sendMessage]);
264	
265	  /* ── Stop audio ── */
266	  const stopAudio = useCallback(() => {
267	    audioRef.current?.pause();
268	    audioRef.current = null;
269	    if (stateRef.current === 'speaking') setState('dormant');
270	  }, [setState]);
271	
272	  /* ── Operator unlock ── */
273	  const submitLock = useCallback(async (e: FormEvent) => {
274	    e.preventDefault();
275	    setLockError('');
276	    try {
277	      const res = await fetch('/api/operator/session', {
278	        method: 'POST',
279	        headers: { 'Content-Type': 'application/json' },
280	        body: JSON.stringify({ token: lockToken.trim() }),
281	      });
282	      if (!res.ok) {
283	        const body = await res.json().catch(() => ({}));
284	        setLockError((body as { error?: string }).error ?? 'Invalid token');
285	        return;
286	      }
287	      setOperatorMode(true);
288	      setShowLockModal(false);
289	      setLockToken('');
290	    } catch {
291	      setLockError('Connection error');
292	    }
293	  }, [lockToken]);
294	
295	  const revokeOperator = useCallback(async () => {
296	    await fetch('/api/operator/session', { method: 'DELETE' });
297	    setOperatorMode(false);
298	  }, []);
299	
300	  // Sync operator mode from runtime metadata when it arrives
301	  useEffect(() => {
302	    if (runtimeMeta?.omegaMode === 'operator') setOperatorMode(true);
303	  }, [runtimeMeta]);
304	
305	  const stateClass = s[`state${voiceState.charAt(0).toUpperCase()}${voiceState.slice(1)}`] ?? '';
306	
307	  return (
308	    <div className={`${s.root} ${stateClass}`}>
309	      <canvas ref={canvasRef} className={s.canvas} />
310	
311	      <Link href="/dashboard" className={s.backLink}>Dashboard</Link>
312	
313	      {/* Operator lock icon — bottom-left */}
314	      <button
315	        type="button"
316	        className={`${s.lockBtn} ${operatorMode ? s.lockBtnActive : ''}`}
317	        onClick={() => operatorMode ? revokeOperator() : setShowLockModal(true)}
318	        title={operatorMode ? 'Operator mode active — click to return to public' : 'Unlock operator mode'}
319	      >
320	        {operatorMode ? '🔓' : '🔒'}
321	      </button>
322	
323	      {/* Unlock modal */}
324	      {showLockModal && (
325	        <div className={s.modalBackdrop} onClick={() => setShowLockModal(false)}>
326	          <div className={s.modal} onClick={(e) => e.stopPropagation()}>
327	            <div className={s.modalTitle}>Operator Access</div>
328	            <form onSubmit={submitLock}>
329	              <input
330	                className={s.modalInput}
331	                type="password"
332	                placeholder="Enter operator token"
333	                value={lockToken}
334	                onChange={(e) => setLockToken(e.target.value)}
335	                autoFocus
336	              />
337	              {lockError && <div className={s.modalError}>{lockError}</div>}
338	              <div className={s.modalActions}>
339	                <button type="submit" className={s.modalBtn} disabled={!lockToken.trim()}>Unlock</button>
340	                <button type="button" className={s.modalBtnMuted} onClick={() => setShowLockModal(false)}>Cancel</button>
341	              </div>
342	            </form>
343	          </div>
344	        </div>
345	      )}
346	
347	      {/* Runtime badge — top right, toggleable */}
348	      {runtimeMeta && (
349	        <button type="button" className={s.runtimeBadge} onClick={() => setShowRuntime(!showRuntime)}>
350	          <span className={s.runtimeDot} />
351	          {runtimeMeta.omegaStack ?? 'sovereign'}
352	        </button>
353	      )}
354	
355	      {showRuntime && runtimeMeta && (
356	        <div className={s.runtimeDropdown}>
357	          <div className={s.rdRow}><span>Stack</span><span>{runtimeMeta.omegaStack ?? '—'}</span></div>
358	          <div className={s.rdRow}><span>Mode</span><span>{runtimeMeta.omegaMode ?? '—'}</span></div>
359	          <div className={s.rdRow}><span>Provider</span><span>{runtimeMeta.provider ?? '—'}</span></div>
360	          <div className={s.rdRow}><span>Outcome</span><span>{runtimeMeta.omegaOutcome ?? '—'}</span></div>
361	          <div className={s.rdRow}><span>Memory</span><span>{runtimeMeta.memoryBackend ?? '—'}</span></div>
362	          <div className={s.rdRow}><span>Risk</span><span>{runtimeMeta.omegaRiskScore ?? '—'}</span></div>
363	          <div className={s.rdRow}><span>Envelope</span><span>{runtimeMeta.omegaEnvelopeVersion ?? '—'}</span></div>
364	          <div className={s.rdRow}><span>Phylactery</span><span className={s.mono}>{runtimeMeta.omegaPhylacteryHead ?? '—'}</span></div>
365	        </div>
366	      )}
367	
368	      <div className={s.main}>
369	        {/* Omega header */}
370	        <div className={s.header}>
371	          <button type="button" className={s.omegaWrapper} onClick={toggleListening} aria-label="Toggle voice input">
372	            <div className={s.omegaGlow} />
373	            <div className={s.innerRing} />
374	            <div className={s.omegaSymbol}>&Omega;</div>
375	          </button>
376	          <div className={s.status}>
377	            {voiceState === 'listening' ? 'Listening...' : voiceState === 'processing' ? 'Thinking...' : voiceState === 'speaking' ? 'Speaking...' : operatorMode ? 'OmegA — Operator' : 'OmegA'}
378	          </div>
379	        </div>
380	
381	        {/* Chat messages */}
382	        <div className={s.chatArea}>
383	          {messages.length === 0 && !streamingText && (
384	            <div className={s.emptyState}>
385	              <div className={s.emptyGreeting}>Hello. I&apos;m OmegA.</div>
386	              <div className={s.emptyHint}>I was built by RY — ask me anything, or just say hello.</div>
387	            </div>
388	          )}
389	
390	          {messages.map((msg, i) => (
391	            <div key={i} className={`${s.msg} ${msg.role === 'user' ? s.msgUser : s.msgOmega}`}>
392	              {msg.role === 'omega' && <span className={s.msgLabel}>&Omega;</span>}
393	              <div className={s.msgText}>{msg.text}</div>
394	            </div>
395	          ))}
396	
397	          {streamingText && (
398	            <div className={`${s.msg} ${s.msgOmega}`}>
399	              <span className={s.msgLabel}>&Omega;</span>
400	              <div className={s.msgText}>{streamingText}<span className={s.cursor} /></div>
401	            </div>
402	          )}
403	
404	          <div ref={messagesEndRef} />
405	        </div>
406	
407	        {/* Input bar — always visible */}
408	        <div className={s.inputBar}>
409	          {voiceState === 'speaking' && (
410	            <button type="button" className={s.stopBtn} onClick={stopAudio} aria-label="Stop audio">
411	              Stop
412	            </button>
413	          )}
414	          <form className={s.inputForm} onSubmit={handleSubmit}>
415	            <button
416	              type="button"
417	              className={`${s.micBtn} ${voiceState === 'listening' ? s.micBtnActive : ''}`}
418	              onClick={toggleListening}
419	              disabled={voiceState === 'processing'}
420	              aria-label="Voice input"
421	            >
422	              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
423	                <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z" />
424	                <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
425	                <line x1="12" x2="12" y1="19" y2="22" />
426	              </svg>
427	            </button>
428	            <input
429	              type="text"
430	              className={s.textInput}
431	              placeholder={voiceState === 'listening' ? 'Listening...' : 'Message OmegA...'}
432	              value={textInput}
433	              onChange={(e) => setTextInput(e.target.value)}
434	              disabled={voiceState === 'processing'}
435	            />
436	            <button type="submit" className={s.sendBtn} disabled={!textInput.trim() || voiceState === 'processing'}>
437	              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
438	                <line x1="22" x2="11" y1="2" y2="13" />
439	                <polygon points="22 2 15 22 11 13 2 9 22 2" />
440	              </svg>
441	            </button>
442	          </form>
443	        </div>
444	      </div>
445	    </div>
446	  );
447	}
