8	/* ── Code block with copy button — react-markdown v10 pattern ───── */
9	// Pre wraps block code; code alone is inline.
10	// eslint-disable-next-line @typescript-eslint/no-explicit-any
11	function PreBlock({ children, ...props }: any) {
12	  // Extract className + text from the nested <code> child
13	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
14	  const codeChild = (children as any)?.props;
15	  const className = codeChild?.className ?? '';
16	  const lang = /language-(\w+)/.exec(className)?.[1];
17	  const text = String(codeChild?.children ?? '').replace(/\n$/, '');
18	
19	  const [copied, setCopied] = useState(false);
20	  const copy = () => {
21	    navigator.clipboard.writeText(text);
22	    setCopied(true);
23	    setTimeout(() => setCopied(false), 2000);
24	  };
25	
26	  return (
27	    <div className={s.codeWrap}>
28	      <div className={s.codeHeader}>
29	        <span className={s.codeLang}>{lang ?? 'code'}</span>
30	        <button className={s.codeCopy} onClick={copy} aria-label="Copy code">
31	          {copied ? '✓ Copied' : 'Copy'}
32	        </button>
33	      </div>
34	      <pre
35	        {...props}
36	        style={{
37	          margin: 0,
38	          padding: '1rem',
39	          background: 'rgba(2, 2, 12, 0.92)',
40	          borderRadius: '0 0 0.75rem 0.75rem',
41	          overflowX: 'auto',
42	          fontSize: '0.85rem',
43	          lineHeight: 1.6,
44	          color: '#c4b5fd',
45	        }}
46	      >
47	        {children}
48	      </pre>
49	    </div>
50	  );
51	}
52	
53	// eslint-disable-next-line @typescript-eslint/no-explicit-any
54	function InlineCode({ children, ...props }: any) {
55	  return (
56	    <code
57	      {...props}
58	      style={{
59	        background: 'rgba(99, 102, 241, 0.12)',
60	        padding: '0.15em 0.4em',
61	        borderRadius: '0.3em',
62	        fontSize: '0.88em',
63	        color: '#c4b5fd',
64	      }}
65	    >
66	      {children}
67	    </code>
68	  );
69	}
