71	/* ── Markdown component overrides ───────────────────────────────── */
72	// eslint-disable-next-line @typescript-eslint/no-explicit-any
73	const mdComponents: any = {
74	  pre: PreBlock,
75	  code: InlineCode,
76	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
77	  table: ({ children }: any) => (
